import React, { useEffect, useState } from 'react';
import { Event, EventCategory } from '../types';
import { api } from '../services/api';
import EventCard from '../components/EventCard';
import { Search, Filter, X, Calendar, Tag, DollarSign, Check } from 'lucide-react';

const Home: React.FC = () => {
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Filter States
  const [showFilters, setShowFilters] = useState(false);
  const [selectedTime, setSelectedTime] = useState<'all' | 'today' | 'tomorrow' | 'week' | 'weekend'>('all');
  const [selectedPrice, setSelectedPrice] = useState<'all' | 'free' | 'paid'>('all');
  const [selectedCategory, setSelectedCategory] = useState<'all' | EventCategory>('all');

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const data = await api.events.getAll();
        setEvents(data);
      } catch (error) {
        console.error("Failed to fetch events", error);
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  // FILTER LOGIC
  const filteredEvents = events.filter(e => {
    const lowerSearch = searchTerm.toLowerCase();
    const orgName = typeof e.organization === 'object' && e.organization !== null && 'name' in e.organization
      ? e.organization.name.toLowerCase() 
      : '';

    const matchesSearch = 
      e.title.toLowerCase().includes(lowerSearch) ||
      e.location.toLowerCase().includes(lowerSearch) ||
      orgName.includes(lowerSearch);

    if (!matchesSearch) return false;
    if (selectedCategory !== 'all' && e.category !== selectedCategory) return false;
    if (selectedPrice === 'free' && e.price > 0) return false;
    if (selectedPrice === 'paid' && e.price === 0) return false;

    if (selectedTime !== 'all') {
        const eventDate = new Date(e.date);
        const today = new Date();
        today.setHours(0,0,0,0);
        const tomorrow = new Date(today);
        tomorrow.setDate(today.getDate() + 1);
        const eventDateNoTime = new Date(eventDate);
        eventDateNoTime.setHours(0,0,0,0);

        if (selectedTime === 'today') {
            if (eventDateNoTime.getTime() !== today.getTime()) return false;
        }
        else if (selectedTime === 'tomorrow') {
            if (eventDateNoTime.getTime() !== tomorrow.getTime()) return false;
        }
        else if (selectedTime === 'week') {
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (eventDateNoTime < today || eventDateNoTime > nextWeek) return false;
        }
        else if (selectedTime === 'weekend') {
            const day = eventDate.getDay(); 
            const isWeekendDay = day === 0 || day === 5 || day === 6;
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (!isWeekendDay || eventDateNoTime > nextWeek || eventDateNoTime < today) return false;
        }
    }
    return true;
  });

  const clearFilters = () => {
      setSelectedTime('all');
      setSelectedPrice('all');
      setSelectedCategory('all');
  };

  const hasActiveFilters = selectedTime !== 'all' || selectedPrice !== 'all' || selectedCategory !== 'all';

  return (
    <div className="min-h-screen bg-gray-900 text-white">
      {/* Hero Section */}
      <div className="bg-slate-950 text-white py-12 md:py-16 relative overflow-hidden border-b border-white/5">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden opacity-10 pointer-events-none">
            <div className="absolute -top-20 -left-20 w-96 h-96 bg-indigo-500 rounded-full mix-blend-screen filter blur-3xl"></div>
            <div className="absolute -bottom-20 -right-20 w-96 h-96 bg-pink-500 rounded-full mix-blend-screen filter blur-3xl"></div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center relative z-10">
          <h1 className="text-3xl md:text-5xl font-bold mb-4 tracking-tight">Find Your Next UniParty</h1>
          <p className="text-lg text-gray-400 mb-8 max-w-2xl mx-auto">
            The official platform for university events. Exclusive parties, networking, and fun.
          </p>

          {/* Search Bar */}
          <div className="max-w-2xl mx-auto relative flex items-center">
            <div className="relative flex-grow">
                <input
                  type="text"
                  placeholder="Search events by name, location..."
                  className="w-full pl-6 pr-12 py-4 rounded-l-full bg-gray-800 text-white focus:outline-none shadow-2xl border-0 ring-1 ring-white/10"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
                <div className="absolute right-4 top-1/2 transform -translate-y-1/2">
                    <Search className="h-5 w-5 text-gray-500" />
                </div>
            </div>
            <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`px-6 py-4 rounded-r-full font-semibold flex items-center transition shadow-2xl ${showFilters || hasActiveFilters ? 'bg-indigo-600 text-white' : 'bg-gray-700 text-gray-300 hover:bg-gray-600'}`}
            >
                <Filter className="h-5 w-5 mr-2" />
                Filters
            </button>
          </div>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
          <div className="bg-gray-800 border-b border-gray-700 shadow-xl animate-in slide-in-from-top-2 duration-200">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
                  <div className="flex justify-between items-center mb-4">
                      <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Filter Events</h3>
                      <button onClick={clearFilters} className="text-sm text-indigo-400 hover:text-indigo-300 hover:underline">
                          Reset All
                      </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {/* Time Filter */}
                      <div>
                          <label className="block text-sm font-medium text-gray-300 mb-2 flex items-center">
                              <Calendar className="w-4 h-4 mr-2 text-indigo-400" /> Time
                          </label>
                          <div className="flex flex-wrap gap-2">
                              {['all', 'today', 'tomorrow', 'week', 'weekend'].map((t) => (
                                  <button
                                    key={t}
                                    onClick={() => setSelectedTime(t as any)}
                                    className={`px-3 py-1.5 rounded-full text-sm border transition ${selectedTime === t ? 'bg-indigo-900 border-indigo-700 text-white font-medium' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                                  >
                                      {t === 'all' ? 'Any Date' : t.charAt(0).toUpperCase() + t.slice(1)}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Category Filter */}
                      <div>
                          <label className="block text-sm font-medium text-gray-300 mb-2 flex items-center">
                              <Tag className="w-4 h-4 mr-2 text-indigo-400" /> Category
                          </label>
                          <div className="flex flex-wrap gap-2">
                              <button
                                onClick={() => setSelectedCategory('all')}
                                className={`px-3 py-1.5 rounded-full text-sm border transition ${selectedCategory === 'all' ? 'bg-indigo-900 border-indigo-700 text-white font-medium' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                              >
                                  All
                              </button>
                              {Object.values(EventCategory).map((cat) => (
                                  <button
                                    key={cat}
                                    onClick={() => setSelectedCategory(cat)}
                                    className={`px-3 py-1.5 rounded-full text-sm border transition ${selectedCategory === cat ? 'bg-indigo-900 border-indigo-700 text-white font-medium' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                                  >
                                      {cat}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Price Filter */}
                      <div>
                          <label className="block text-sm font-medium text-gray-300 mb-2 flex items-center">
                              <DollarSign className="w-4 h-4 mr-2 text-indigo-400" /> Price
                          </label>
                          <div className="flex flex-wrap gap-2">
                              {[
                                  { id: 'all', label: 'Any Price' }, 
                                  { id: 'free', label: 'Free' }, 
                                  { id: 'paid', label: 'Paid' }
                              ].map((p) => (
                                  <button
                                    key={p.id}
                                    onClick={() => setSelectedPrice(p.id as any)}
                                    className={`px-3 py-1.5 rounded-full text-sm border transition ${selectedPrice === p.id ? 'bg-indigo-900 border-indigo-700 text-white font-medium' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                                  >
                                      {p.label}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Active Filters Chips */}
      {!showFilters && hasActiveFilters && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center space-x-2 overflow-x-auto">
              <span className="text-xs font-semibold text-gray-500 uppercase mr-2">Active:</span>
              {selectedTime !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-indigo-900/50 text-indigo-300 border border-indigo-800/50">
                      {selectedTime}
                      <button onClick={() => setSelectedTime('all')} className="ml-2"><X className="w-3 h-3"/></button>
                  </span>
              )}
              {selectedCategory !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-indigo-900/50 text-indigo-300 border border-indigo-800/50">
                      {selectedCategory}
                      <button onClick={() => setSelectedCategory('all')} className="ml-2"><X className="w-3 h-3"/></button>
                  </span>
              )}
              {selectedPrice !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-indigo-900/50 text-indigo-300 border border-indigo-800/50">
                      {selectedPrice}
                      <button onClick={() => setSelectedPrice('all')} className="ml-2"><X className="w-3 h-3"/></button>
                  </span>
              )}
              <button onClick={clearFilters} className="text-xs text-gray-500 hover:text-red-400 underline ml-auto">Clear All</button>
          </div>
      )}

      {/* Events Grid */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-white">
              {searchTerm ? 'Search Results' : 'Upcoming Events'}
              <span className="ml-2 text-sm font-normal text-gray-500">({filteredEvents.length})</span>
          </h2>
        </div>

        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
             {[1, 2, 3].map(i => (
               <div key={i} className="bg-gray-800 rounded-xl h-96 animate-pulse"></div>
             ))}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredEvents.length > 0 ? (
              filteredEvents.map(event => (
                <EventCard key={event._id} event={event} />
              ))
            ) : (
              <div className="col-span-full py-16 text-center">
                <div className="bg-gray-800 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4 border border-gray-700">
                    <Search className="w-8 h-8 text-gray-600" />
                </div>
                <h3 className="text-lg font-bold text-white mb-1">No events found</h3>
                <p className="text-gray-500">Try adjusting your filters or search terms.</p>
                <button onClick={clearFilters} className="mt-4 text-indigo-400 font-semibold hover:underline">Clear all filters</button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { api } from '../services/api';
import { Eye, EyeOff } from 'lucide-react';

const Auth: React.FC = () => {
  const [viewState, setViewState] = useState<'login' | 'register' | 'forgot'>('login');
  const { login, register, isLoading } = useAuth();
  const navigate = useNavigate();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [name, setName] = useState('');
  const [surname, setSurname] = useState('');
  const [description, setDescription] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.STUDENTE);
  const [error, setError] = useState('');
  const [infoMessage, setInfoMessage] = useState('');
  const [acceptedTerms, setAcceptedTerms] = useState(false);

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isValidPassword = (password: string) => {
    if (password.length < 6) return false;
    if (!/[A-Z]/.test(password)) return false;
    if (!/[0-9]/.test(password)) return false;
    if (!/[!@#$%^&*(),.?":{}|<>]/.test(password)) return false;
    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setInfoMessage('');

    if (viewState === 'forgot') {
        if (!email || !isValidEmail(email)) {
            setError("Please enter a valid email.");
            return;
        }
        try {
            await api.auth.forgotPassword(email);
            setInfoMessage("Se l'email esiste, riceverai un link di recupero a breve.");
        } catch (err: any) {
            setError(err.message || 'Failed to request password reset');
        }
        return;
    }

    if (!email || !password) {
        setError("Please fill in all fields");
        return;
    }

    if (!isValidEmail(email)) {
        setError("Please enter a valid real email address.");
        return;
    }

    if (viewState === 'register') {
        if (!isValidPassword(password)) {
            setError("Password must be at least 6 characters long and contain at least: 1 uppercase letter, 1 number, and 1 special character.");
            return;
        }
        if (!acceptedTerms) {
            setError("Devi accettare i Termini e Condizioni e la Privacy Policy per registrarti.");
            return;
        }
    }

    try {
      if (viewState === 'login') {
        await login(email, password);
      } else {
        await register({
          email,
          password, 
          name,
          role,
          ...(role === UserRole.STUDENTE ? { surname } : { description })
        });
      }
      navigate('/');
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    }
  };

  const toggleMode = () => {
      setViewState(viewState === 'login' ? 'register' : 'login');
      setError('');
      setInfoMessage('');
      setAcceptedTerms(false);
  };

  return (
    <div className="min-h-[calc(100vh-64px)] flex items-center justify-center bg-gray-900 px-4">
      <div className="bg-gray-800 rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-gray-700">
        <div className="px-8 py-8">
            <h2 className="text-3xl font-bold text-center text-white mb-2">
              {viewState === 'login' && 'Welcome Back'}
              {viewState === 'register' && 'Join UniParty'}
              {viewState === 'forgot' && 'Recupero Password'}
            </h2>
            <p className="text-center text-gray-400 mb-8">
              {viewState === 'login' && 'Login to access your vouchers'}
              {viewState === 'register' && 'Create an account to start partying'}
              {viewState === 'forgot' && 'Inserisci la tua email per reimpostare la password'}
            </p>

            {error && (
                <div className="bg-red-900/20 text-red-400 p-3 rounded-lg mb-4 text-sm text-center border border-red-900/30">
                    {error}
                </div>
            )}

            {infoMessage && (
                <div className="bg-green-900/20 text-green-400 p-3 rounded-lg mb-4 text-sm text-center border border-green-900/30">
                    {infoMessage}
                </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">

              {viewState === 'register' && (
                <div className="flex bg-gray-900 p-1 rounded-lg mb-6 border border-gray-700">
                  <button
                    type="button"
                    className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${role === UserRole.STUDENTE ? 'bg-gray-700 shadow text-indigo-400' : 'text-gray-500'}`}
                    onClick={() => setRole(UserRole.STUDENTE)}
                  >
                    Student
                  </button>
                  <button
                    type="button"
                    className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${role === UserRole.ASSOCIAZIONE ? 'bg-gray-700 shadow text-indigo-400' : 'text-gray-500'}`}
                    onClick={() => setRole(UserRole.ASSOCIAZIONE)}
                  >
                    Association
                  </button>
                </div>
              )}

              {viewState === 'register' && (
                  <>
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Name {role === UserRole.ASSOCIAZIONE ? '(Organization)' : ''}</label>
                        <input
                            type="text"
                            className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            required
                        />
                    </div>
                    {role === UserRole.STUDENTE && (
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Surname</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                value={surname}
                                onChange={(e) => setSurname(e.target.value)}
                                required
                            />
                        </div>
                    )}
                    {role === UserRole.ASSOCIAZIONE && (
                         <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Description</label>
                            <textarea
                                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                rows={2}
                                required
                            />
                        </div>
                    )}
                  </>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Email</label>
                <input
                  type="email"
                  className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>

              {viewState !== 'forgot' && (
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Password</label>
                    <div className="relative">
                        <input
                        type={showPassword ? 'text' : 'password'}
                        className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white pr-10"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                        />
                        <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-white focus:outline-none"
                        >
                            {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                        </button>
                    </div>
                    {viewState === 'register' && (
                        <p className="text-xs text-gray-500 mt-1">
                            Min. 6 chars, 1 uppercase, 1 number, 1 special char.
                        </p>
                    )}
                    {viewState === 'login' && (
                        <div className="text-right mt-1">
                            <button type="button" onClick={() => setViewState('forgot')} className="text-xs text-indigo-400 hover:underline">
                                Password dimenticata?
                            </button>
                        </div>
                    )}
                  </div>
              )}

              {viewState === 'register' && (
                  <div className="flex items-start mt-4">
                      <div className="flex items-center h-5">
                          <input
                              id="terms"
                              name="terms"
                              type="checkbox"
                              checked={acceptedTerms}
                              onChange={(e) => setAcceptedTerms(e.target.checked)}
                              className="h-4 w-4 bg-gray-700 text-indigo-600 focus:ring-indigo-500 border-gray-600 rounded cursor-pointer"
                              required
                          />
                      </div>
                      <div className="ml-3 text-sm">
                          <label htmlFor="terms" className="font-medium text-gray-400">
                              Ho letto e accetto i <Link to="/terms" className="text-indigo-400 hover:underline">Termini e Condizioni</Link> e la <Link to="/privacy" className="text-indigo-400 hover:underline">Privacy Policy</Link>.
                          </label>
                      </div>
                  </div>
              )}

              <button
                type="submit"
                disabled={isLoading || (viewState === 'register' && !acceptedTerms)}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-lg transition-colors shadow-lg disabled:opacity-50 disabled:cursor-not-allowed mt-6"
              >
                {isLoading ? 'Processing...' : (
                    viewState === 'login' ? 'Login' : 
                    viewState === 'register' ? 'Sign Up' : 'Invia Link di Recupero'
                )}
              </button>
            </form>
        </div>
        <div className="bg-gray-900 px-8 py-4 text-center border-t border-gray-700">
            {viewState === 'forgot' ? (
                <button 
                    onClick={() => setViewState('login')}
                    className="text-indigo-400 font-semibold hover:underline text-sm"
                >
                    Torna al Login
                </button>
            ) : (
                <p className="text-sm text-gray-400">
                    {viewState === 'login' ? "Don't have an account? " : "Already have an account? "}
                    <button 
                        onClick={toggleMode}
                        className="text-indigo-400 font-semibold hover:underline"
                    >
                        {viewState === 'login' ? 'Register' : 'Login'}
                    </button>
                </p>
            )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { Event, UserRole } from '../types';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { MapPin, Calendar, Clock, Info, Minus, Plus, Ban, Trash2, Pencil, X, Save, Image as ImageIcon, BarChart, List, FileText, CheckCircle, GraduationCap, BookOpen, ChevronRight, ShieldCheck, Flag, AlertTriangle, ArrowLeft, DollarSign, Lock } from 'lucide-react';

const EventDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [event, setEvent] = useState<Event | null>(null);
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [purchasing, setPurchasing] = useState(false);

  const [ticketNames, setTicketNames] = useState<string[]>(['']);
  const [ticketMatricolas, setTicketMatricolas] = useState<string[]>(['']);
  const [ticketCorsoStudi, setTicketCorsoStudi] = useState<string[]>(['']);
  const [selectedPrList, setSelectedPrList] = useState<string>(""); 
  const [acceptedTerms, setAcceptedTerms] = useState(false);
  const [prStats, setPrStats] = useState<{ [key: string]: number } | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState<Partial<Event>>({});
  const [editPriceString, setEditPriceString] = useState('0');
  const [currentEditPrInput, setCurrentEditPrInput] = useState('');
  const [saving, setSaving] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [reportReason, setReportReason] = useState('');
  const [isSubmittingReport, setIsSubmittingReport] = useState(false);

  const isOwner = user && event && (
      (typeof event.organization === 'string' && event.organization === user._id) ||
      (typeof event.organization !== 'string' && event.organization._id === user._id)
  );

  useEffect(() => {
    if (id) {
      api.events.getById(id).then(data => {
          setEvent(data || null);
          if(data) {
              setEditForm({
                  title: data.title,
                  description: data.description,
                  longDescription: data.longDescription,
                  date: data.date.split('T')[0], 
                  time: data.time,
                  location: data.location,
                  image: data.image,
                  maxCapacity: data.maxCapacity,
                  prLists: data.prLists || [],
                  requiresMatricola: data.requiresMatricola || false,
                  requiresCorsoStudi: data.requiresCorsoStudi || false,
              });
              setEditPriceString(data.price.toString());
          }
      }).finally(() => setLoading(false));
    }
  }, [id]);

  useEffect(() => {
      if (isOwner && id) {
          api.events.getEventStats(id).then(setPrStats);
      }
  }, [isOwner, id]);

  useEffect(() => {
    setTicketNames(prev => {
        const newNames = [...prev];
        if (quantity > prev.length) {
            for (let i = prev.length; i < quantity; i++) newNames.push('');
        } else {
            return newNames.slice(0, quantity);
        }
        return newNames;
    });
    setTicketMatricolas(prev => {
        const newMats = [...prev];
        if (quantity > prev.length) {
            for (let i = prev.length; i < quantity; i++) newMats.push('');
        } else {
            return newMats.slice(0, quantity);
        }
        return newMats;
    });
    setTicketCorsoStudi(prev => {
        const newCors = [...prev];
        if (quantity > prev.length) {
            for (let i = prev.length; i < quantity; i++) newCors.push('');
        } else {
            return newCors.slice(0, quantity);
        }
        return newCors;
    });
  }, [quantity]);

  const handlePurchase = async () => {
    if (!user) { navigate('/auth'); return; }
    if (user.role !== UserRole.STUDENTE) { alert("Solo gli studenti possono prenotare voucher."); return; }
    if (ticketNames.some(name => name.trim() === '')) { alert("Inserisci il nome per ogni voucher."); return; }
    if (!acceptedTerms) { alert("Devi accettare i Termini del Servizio per procedere."); return; }

    if (event) {
      setPurchasing(true);
      try {
        const redirectUrl = await api.payments.createCheckoutSession(
            event._id, quantity, user._id, ticketNames, selectedPrList || "Nessuna lista",
            event.requiresMatricola ? ticketMatricolas : undefined,
            event.requiresCorsoStudi ? ticketCorsoStudi : undefined
        );
        if (redirectUrl) window.location.hash = redirectUrl;
      } catch (error) { alert("Prenotazione fallita."); } finally { setPurchasing(false); }
    }
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    e.currentTarget.src = "https://picsum.photos/800/400?random=999"; 
  };

