import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { Search, UserPlus, UserCheck, Briefcase } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const SearchAssociations: React.FC = () => {
  const { user, refreshUser } = useAuth();
  const navigate = useNavigate();
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [followLoading, setFollowLoading] = useState<string | null>(null);

  // Debounce logic could be added here, but simple submit/effect for now
  useEffect(() => {
    if (query.length > 2) {
      const search = async () => {
        setLoading(true);
        try {
          const data = await api.auth.searchAssociations(query);
          setResults(data);
        } catch (e) {
          console.error(e);
        } finally {
          setLoading(false);
        }
      };
      const timeoutId = setTimeout(search, 500);
      return () => clearTimeout(timeoutId);
    } else {
        setResults([]);
    }
  }, [query]);

  const handleToggleFollow = async (associationId: string) => {
      setFollowLoading(associationId);
      try {
          await api.auth.toggleFollow(associationId);
          await refreshUser(); // Update context to reflect new following list
      } catch (e) {
          console.error("Follow error", e);
      } finally {
          setFollowLoading(null);
      }
  };

  const isFollowing = (associationId: string) => {
      if (!user?.followedAssociations) return false;
      // Depending on if populate ran, it might be string ID or User object
      return user.followedAssociations.some((f: any) => 
          (typeof f === 'string' ? f : f._id) === associationId
      );
  };

  if (!user || user.role !== UserRole.STUDENTE) {
      return (
          <div className="p-8 text-center bg-gray-900 text-white min-h-screen">
              <p className="text-gray-400">Questa funzione è riservata agli studenti.</p>
              <button onClick={() => navigate('/')} className="text-indigo-400 mt-4 font-bold hover:text-indigo-300 transition">Torna alla Home</button>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-gray-900 py-8 px-4 sm:px-6 lg:px-8 text-white">
      <div className="max-w-2xl mx-auto">
        <h1 className="text-2xl font-bold text-white mb-6 flex items-center">
            <Search className="w-7 h-7 mr-2 text-indigo-400" />
            Cerca Associazioni
        </h1>

        <div className="relative mb-8">
            <input 
                type="text" 
                placeholder="Digita il nome di un'associazione..."
                value={query}
                onChange={e => setQuery(e.target.value)}
                className="w-full pl-12 pr-4 py-4 border border-gray-700 rounded-xl shadow-lg bg-gray-800 focus:ring-2 focus:ring-indigo-500 outline-none text-lg text-white placeholder-gray-500"
            />
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 w-6 h-6 text-gray-500" />
        </div>

        {loading ? (
             <div className="text-center py-12">
                 <div className="w-10 h-10 border-4 border-indigo-900 border-t-indigo-500 rounded-full animate-spin mx-auto mb-2"></div>
                 <p className="text-gray-500">Ricerca in corso...</p>
             </div>
        ) : (
            <div className="space-y-4">
                {results.length > 0 ? (
                    results.map(assoc => (
                        <div 
                            key={assoc._id} 
                            onClick={() => navigate(`/association/${assoc._id}`)}
                            className="bg-gray-800 rounded-xl shadow-sm p-4 flex items-center justify-between transition hover:shadow-indigo-500/5 cursor-pointer hover:bg-gray-750 border border-gray-700"
                        >
                            <div className="flex items-center">
                                <div className="w-12 h-12 bg-gray-700 rounded-full overflow-hidden mr-4 flex-shrink-0 border border-gray-600 shadow-inner">
                                    {assoc.profileImage ? (
                                        <img src={assoc.profileImage} alt={assoc.name} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center bg-gray-900 text-indigo-400">
                                            <Briefcase className="w-6 h-6" />
                                        </div>
                                    )}
                                </div>
                                <div>
                                    <h3 className="font-bold text-white text-lg">{assoc.name}</h3>
                                    <p className="text-sm text-gray-400">{assoc.followersCount || 0} Followers</p>
                                </div>
                            </div>
                            <button
                                onClick={(e) => {
                                    e.stopPropagation(); // Prevent navigation when clicking follow
                                    handleToggleFollow(assoc._id);
                                }}
                                disabled={followLoading === assoc._id}
                                className={`px-4 py-2 rounded-full font-bold text-sm flex items-center transition shadow-sm ${
                                    isFollowing(assoc._id) 
                                    ? 'bg-gray-700 text-gray-300 hover:bg-gray-600 border border-gray-600' 
                                    : 'bg-indigo-600 text-white hover:bg-indigo-700'
                                }`}
                            >
                                {followLoading === assoc._id ? (
                                    <span className="opacity-50">...</span>
                                ) : isFollowing(assoc._id) ? (
                                    <>
                                        <UserCheck className="w-4 h-4 mr-2" />
                                        Segui già
                                    </>
                                ) : (
                                    <>
                                        <UserPlus className="w-4 h-4 mr-2" />
                                        Segui
                                    </>
                                )}
                            </button>
                        </div>
                    ))
                ) : (
                    query.length > 2 && (
                        <div className="text-center py-12 text-gray-500">
                            Nessuna associazione trovata.
                        </div>
                    )
                )}

                {query.length <= 2 && (
                     <div className="text-center py-12 text-gray-500 bg-gray-800/30 rounded-2xl border border-dashed border-gray-700 p-8">
                         Inizia a digitare per cercare organizzatori da seguire.
                         <br/><span className="text-indigo-400/80">Riceverai una notifica email quando pubblicheranno nuovi eventi!</span>
                     </div>
                )}
            </div>
        )}
      </div>
    </div>
  );
};

export default SearchAssociations;

import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import { Bell, CheckCircle, ArrowRight } from 'lucide-react';

interface Notification {
  _id: string;
  title: string;
  message: string;
  url: string;
  isRead: boolean;
  createdAt: string;
}

const Notifications: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) {
      navigate('/');
      return;
    }
    fetchNotifications();
  }, [user]);

  const fetchNotifications = async () => {
    try {
      const data = await api.notifications.getAll();
      setNotifications(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleNotificationClick = async (notification: Notification) => {
    if (!notification.isRead) {
      await api.notifications.markAsRead(notification._id);
    }
    navigate(notification.url);
  };

  const markAllAsRead = async () => {
      // Optimistic update
      const updated = notifications.map(n => ({...n, isRead: true}));
      setNotifications(updated);

      // Async requests
      for(const n of notifications) {
          if(!n.isRead) api.notifications.markAsRead(n._id);
      }
  };

  return (
    <div className="min-h-screen bg-gray-900 py-12 px-4 sm:px-6 lg:px-8 text-white">
      <div className="max-w-3xl mx-auto">
        <div className="flex items-center justify-between mb-8">
            <div className="flex items-center">
                <Bell className="w-8 h-8 text-indigo-400 mr-3" />
                <h1 className="text-3xl font-bold text-white">Notifications</h1>
            </div>
            {notifications.some(n => !n.isRead) && (
                <button 
                    onClick={markAllAsRead}
                    className="text-sm font-medium text-indigo-400 hover:text-indigo-300 transition"
                >
                    Mark all as read
                </button>
            )}
        </div>

        {loading ? (
             <div className="space-y-4">
                {[1, 2, 3].map(i => (
                  <div key={i} className="bg-gray-800 rounded-xl h-24 shadow-sm animate-pulse border border-gray-700"></div>
                ))}
             </div>
        ) : notifications.length === 0 ? (
            <div className="text-center py-20 bg-gray-800 rounded-2xl shadow-sm border border-gray-700">
                <div className="w-16 h-16 bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-600">
                    <Bell className="w-8 h-8 text-gray-500" />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">No notifications</h3>
                <p className="text-gray-500">You're all caught up!</p>
            </div>
        ) : (
            <div className="space-y-4">
                {notifications.map(notif => (
                    <div 
                        key={notif._id} 
                        onClick={() => handleNotificationClick(notif)}
                        className={`p-4 rounded-xl shadow-sm border cursor-pointer transition flex items-start gap-4 ${
                            notif.isRead ? 'bg-gray-800 border-gray-700 opacity-60' : 'bg-indigo-900/20 border-indigo-900/50 border-l-4 border-l-indigo-500'
                        }`}
                    >
                        <div className={`mt-1 p-2 rounded-full ${notif.isRead ? 'bg-gray-700 text-gray-500' : 'bg-indigo-950 text-indigo-400 shadow-inner'}`}>
                            {notif.isRead ? <CheckCircle className="w-5 h-5"/> : <Bell className="w-5 h-5"/>}
                        </div>
                        <div className="flex-1">
                            <h4 className={`font-bold ${notif.isRead ? 'text-gray-400' : 'text-white'}`}>{notif.title}</h4>
                            <p className="text-sm text-gray-400 mt-1 leading-relaxed">{notif.message}</p>
                            <p className="text-[10px] text-gray-600 mt-2 font-medium uppercase tracking-wider">{new Date(notif.createdAt).toLocaleDateString()} {new Date(notif.createdAt).toLocaleTimeString()}</p>
                        </div>
                        <ArrowRight className="w-5 h-5 text-gray-600 self-center" />
                    </div>
                ))}
            </div>
        )}
      </div>
    </div>
  );
};

export default Notifications;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { UserRole, Event, User } from '../types';
import EventCard from '../components/EventCard';
import { Users, Globe, UserPlus, UserCheck, Briefcase, Calendar, ArrowLeft } from 'lucide-react';

const AssociationProfile: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, refreshUser } = useAuth();

  const [association, setAssociation] = useState<User | null>(null);
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [followLoading, setFollowLoading] = useState(false);

  useEffect(() => {
    if (id) {
        setLoading(true);
        // 1. Fetch Association Public Details
        const fetchProfile = api.auth.getPublicProfile(id);
        // 2. Fetch Active/Future Events
        const fetchEvents = api.events.getPublicEventsByOrg(id);

        Promise.all([fetchProfile, fetchEvents])
            .then(([userData, eventsData]) => {
                setAssociation(userData);
                setEvents(eventsData);
            })
            .catch(err => {
                console.error("Failed to load profile", err);
            })
            .finally(() => setLoading(false));
    }
  }, [id]);

  const handleToggleFollow = async () => {
    if (!user) {
        navigate('/auth'); // Redirect to login if guest
        return;
    }

    if (!association) return;

    setFollowLoading(true);
    try {
        await api.auth.toggleFollow(association._id);
        await refreshUser(); // Update context
        // Manually update local follower count for immediate feedback
        const isFollowing = user?.followedAssociations?.some((f: any) => 
            (typeof f === 'string' ? f : f._id) === association._id
        );

        setAssociation(prev => prev ? ({
            ...prev,
            followersCount: isFollowing ? (prev.followersCount || 1) - 1 : (prev.followersCount || 0) + 1
        }) : null);

    } catch (e) {
        console.error("Follow error", e);
    } finally {
        setFollowLoading(false);
    }
  };

  const isFollowing = () => {
      if (!user?.followedAssociations || !association) return false;
      return user.followedAssociations.some((f: any) => 
          (typeof f === 'string' ? f : f._id) === association._id
      );
  };

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-900 text-white">
               <div className="w-12 h-12 border-4 border-indigo-900 border-t-indigo-500 rounded-full animate-spin"></div>
          </div>
      );
  }

  if (!association) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center bg-gray-900 p-4 text-white">
              <h2 className="text-xl font-bold text-white mb-2">Associazione non trovata</h2>
              <button onClick={() => navigate('/')} className="text-indigo-400 font-semibold hover:text-indigo-300 transition">Torna alla Home</button>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-gray-900 pb-20 text-white">
      {/* HEADER / BANNER */}
      <div className="bg-gray-800 shadow-sm border-b border-gray-700">
          <div className="max-w-4xl mx-auto px-4 py-8">
               <button onClick={() => navigate(-1)} className="mb-6 flex items-center text-gray-400 hover:text-white transition">
                   <ArrowLeft className="w-5 h-5 mr-2" /> Indietro
               </button>

               <div className="flex flex-col md:flex-row items-center md:items-start gap-6 md:gap-10">
                    {/* Avatar */}
                    <div className="flex-shrink-0">
                        <div className="w-32 h-32 md:w-40 md:h-40 rounded-full border-4 border-gray-700 shadow-lg overflow-hidden bg-gray-900">
                            {association.profileImage ? (
                                <img src={association.profileImage} alt={association.name} className="w-full h-full object-cover" />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center bg-indigo-900/20 text-indigo-400">
                                    <Briefcase className="w-16 h-16" />
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Info */}
                    <div className="flex-1 text-center md:text-left space-y-4">
                        <div>
                            <h1 className="text-3xl font-bold text-white">{association.name}</h1>
                            {association.description && (
                                <p className="text-gray-400 mt-2 whitespace-pre-line leading-relaxed max-w-2xl">
                                    {association.description}
                                </p>
                            )}
                        </div>

                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-6 text-sm">
                            <div className="flex items-center text-gray-300 font-medium bg-gray-900 px-3 py-1 rounded-full border border-gray-700">
                                <Users className="w-4 h-4 mr-2 text-indigo-400" />
                                {association.followersCount || 0} Followers
                            </div>

                            {association.socialLinks && (
                                <div className="flex items-center text-gray-500">
                                    <Globe className="w-4 h-4 mr-2 text-indigo-900/50" />
                                    <span className="truncate max-w-[200px]">{association.socialLinks}</span>
                                </div>
                            )}
                        </div>

                        {/* Follow Button (Only for Students or Guests) */}
                        {(!user || user.role === UserRole.STUDENTE) && (
                             <div className="pt-2">
                                 <button
                                    onClick={handleToggleFollow}
                                    disabled={followLoading}
                                    className={`px-8 py-2.5 rounded-full font-bold shadow-lg transition transform active:scale-95 flex items-center mx-auto md:mx-0 ${
                                        isFollowing() 
                                        ? 'bg-gray-700 text-gray-300 border border-gray-600 hover:bg-gray-650' 
                                        : 'bg-indigo-600 text-white hover:bg-indigo-700'
                                    }`}
                                >
                                    {followLoading ? (
                                        <span className="opacity-70">Updating...</span>
                                    ) : isFollowing() ? (
                                        <>
                                            <UserCheck className="w-5 h-5 mr-2" />
                                            Segui già
                                        </>
                                    ) : (
                                        <>
                                            <UserPlus className="w-5 h-5 mr-2" />
                                            Segui
                                        </>
                                    )}
                                </button>
                             </div>
                        )}
                    </div>
               </div>
          </div>
      </div>

      {/* EVENTS GRID */}
      <div className="max-w-6xl mx-auto px-4 py-12">
           <h2 className="text-2xl font-bold text-white mb-8 flex items-center">
               <Calendar className="w-6 h-6 mr-3 text-indigo-400" />
               Prossimi Eventi
           </h2>

           {events.length > 0 ? (
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                   {events.map(event => (
                       <EventCard key={event._id} event={event} />
                   ))}
               </div>
           ) : (
               <div className="text-center py-20 bg-gray-800 rounded-2xl shadow-sm border border-gray-700">
                   <div className="w-16 h-16 bg-gray-900/50 rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-700">
                       <Calendar className="w-8 h-8 text-gray-600" />
                   </div>
                   <p className="text-gray-400 font-medium">Nessun evento in programma al momento.</p>
                   <p className="text-sm text-gray-500 mt-1 italic">Segui l'associazione per ricevere notifiche sui nuovi eventi!</p>
               </div>
           )}
      </div>
    </div>
  );
};

export default AssociationProfile;

import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { User, Event, Ticket, UserRole, Report } from '../types';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Shield, User as UserIcon, Calendar, CheckCircle, XCircle, Trash2, RefreshCw, Ticket as TicketIcon, Search, Eye, Filter, BarChart, X, TrendingUp, DollarSign, Heart, GraduationCap, Clock, Users, Flag, AlertTriangle } from 'lucide-react';

type UserFilter = 'all' | 'studente' | 'associazione';

const AdminDashboard: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  // Tab State derived from URL
  const activeTab = (searchParams.get('tab') as 'users' | 'events' | 'reports') || 'users';

  // Data State
  const [users, setUsers] = useState<User[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [userFilter, setUserFilter] = useState<UserFilter>('all');

  // Modal Ticket State
  const [isTicketModalOpen, setIsTicketModalOpen] = useState(false);
  const [selectedUserTickets, setSelectedUserTickets] = useState<Ticket[]>([]);
  const [selectedUserName, setSelectedUserName] = useState('');
  const [modalLoading, setModalLoading] = useState(false);

  // Modal Stats State
  const [isStatsModalOpen, setIsStatsModalOpen] = useState(false);
  const [selectedEventStats, setSelectedEventStats] = useState<{ [key: string]: number } | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [statsLoading, setStatsLoading] = useState(false);

  // Moderation Modal State
  const [isModModalOpen, setIsModModalOpen] = useState(false);
  const [modTargetEvent, setModTargetEvent] = useState<Event | null>(null);
  const [deleteReason, setDeleteReason] = useState('');
  const [isModLoading, setIsModLoading] = useState(false);

  useEffect(() => {
    // Access Control
    if (!user || user.role !== UserRole.ADMIN) {
        navigate('/');
        return;
    }

    fetchData();
  }, [user, navigate, activeTab]);

  const fetchData = async () => {
      setLoading(true);
      try {
          if (activeTab === 'users') {
              const data = await api.admin.getAllUsers();
              setUsers(data);
          } else if (activeTab === 'events') {
              const data = await api.admin.getAllEvents();
              setEvents(data);
          } else if (activeTab === 'reports') {
              const data = await api.reports.getAll();
              setReports(data);
          }
      } catch (e) {
          console.error("Admin fetch error", e);
      } finally {
          setLoading(false);
      }
  };

  const handleTabChange = (tab: 'users' | 'events' | 'reports') => {
      setSearchParams({ tab });
  };

  const handleVerifyUser = async (userId: string) => {
      if(!window.confirm("Cambiare stato di verifica utente?")) return;
      try {
          await api.admin.verifyUser(userId);
          fetchData(); // Refresh list
      } catch(e) {
          alert("Errore verifica utente");
      }
  };

  const handleRestoreUser = async (userId: string) => {
      if(!window.confirm("Ripristinare questo utente cancellato?")) return;
      try {
          await api.admin.restoreUser(userId);
          fetchData();
      } catch(e) {
          alert("Errore ripristino utente");
      }
  };

  const handleViewTickets = async (userId: string, userName: string) => {
      setIsTicketModalOpen(true);
      setSelectedUserName(userName);
      setModalLoading(true);
      try {
          const tickets = await api.admin.getUserTickets(userId);
          setSelectedUserTickets(tickets);
      } catch(e) {
          console.error("Failed to fetch tickets", e);
          setSelectedUserTickets([]);
      } finally {
          setModalLoading(false);
      }
  };

  const handleViewStats = async (event: Event) => {
      setIsStatsModalOpen(true);
      setSelectedEvent(event);
      setStatsLoading(true);
      try {
          const stats = await api.events.getEventStats(event._id);
          setSelectedEventStats(stats);
      } catch (e) {
          console.error("Failed to fetch stats", e);
          setSelectedEventStats(null);
      } finally {
          setStatsLoading(false);
      }
  };

  const handleOpenModeration = (event: Event) => {
      setModTargetEvent(event);
      setIsModModalOpen(true);
      setDeleteReason('');
  };

  const handleModDelete = async () => {
      if (!modTargetEvent || !deleteReason.trim()) return;
      setIsModLoading(true);
      try {
          await api.admin.deleteEventWithReason(modTargetEvent._id, deleteReason);
          alert("Evento rimosso e organizzatore notificato.");
          setIsModModalOpen(false);
          fetchData();
      } catch (err) {
          alert("Errore durante la rimozione.");
      } finally {
          setIsModLoading(false);
      }
  };

  const filteredUsers = users.filter(u => {
      const matchesSearch = u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            u.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRole = userFilter === 'all' || u.role === userFilter;
      return matchesSearch && matchesRole;
  });

  const filteredEvents = events.filter(e => 
      e.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (typeof e.organization === 'object' && e.organization.name.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const getTicketStatusBadge = (ticket: Ticket) => {
      if (ticket.status === 'entered') {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-yellow-900/30 text-yellow-500 border border-yellow-900/50">IN SALA</span>;
      }
      if (ticket.status === 'completed') {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-blue-900/30 text-blue-400 border border-blue-900/50">COMPLETATO</span>;
      }
      if (ticket.status === 'valid' || ticket.status === 'active' || (!ticket.used && !ticket.status)) {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-green-900/30 text-green-400 border border-green-900/50">VALIDO</span>;
      }
      // Fallback legacy used
      return <span className="px-3 py-1 rounded-full text-xs font-bold bg-gray-700 text-gray-400 border border-gray-600">USATO</span>;
  };

  if (!user || user.role !== UserRole.ADMIN) return null;

  return (
    <div className="min-h-screen bg-gray-900 p-4 md:p-8 text-white">
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
            <div className="flex items-center">
                <Shield className="w-10 h-10 text-indigo-400 mr-3" />
                <h1 className="text-3xl font-bold text-white">Admin Dashboard</h1>
            </div>
            <div className="bg-gray-800 rounded-lg shadow-lg p-2 flex space-x-2 border border-gray-700">
                <button 
                    onClick={() => handleTabChange('users')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'users' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-700'}`}
                >
                    <div className="flex items-center">
                        <UserIcon className="w-4 h-4 mr-2" />
                        Utenti
                    </div>
                </button>
                <button 
                    onClick={() => handleTabChange('events')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'events' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-700'}`}
                >
                    <div className="flex items-center">
                        <Calendar className="w-4 h-4 mr-2" />
                        Eventi
                    </div>
                </button>
                <button 
                    onClick={() => handleTabChange('reports')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'reports' ? 'bg-red-600 text-white' : 'text-gray-400 hover:bg-gray-700'}`}
                >
                    <div className="flex items-center">
                        <Flag className="w-4 h-4 mr-2" />
                        Segnalazioni
                    </div>
                </button>
            </div>
        </div>

        {/* Filter Bar */}
        {activeTab !== 'reports' && (
            <div className="mb-6 flex flex-col md:flex-row gap-4">
                <div className="relative flex-grow">
                    <input 
                        type="text"
                        placeholder={activeTab === 'users' ? "Cerca utente per nome o email..." : "Cerca evento per titolo o organizzatore..."}
                        className="w-full pl-10 pr-4 py-3 bg-gray-800 border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm text-white placeholder-gray-500"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    <Search className="w-5 h-5 text-gray-500 absolute left-3 top-3.5" />
                </div>

                {activeTab === 'users' && (
                    <div className="flex items-center bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 shadow-sm">
                        <Filter className="w-5 h-5 text-gray-500 mr-2" />
                        <select 
                            value={userFilter}
                            onChange={(e) => setUserFilter(e.target.value as UserFilter)}
                            className="bg-transparent outline-none text-gray-300 font-medium cursor-pointer"
                        >
                            <option value="all">Tutti i Ruoli</option>
                            <option value="studente">Studenti</option>
                            <option value="associazione">Associazioni</option>
                        </select>
                    </div>
                )}
            </div>
        )}

        {/* Content */}
        <div className="bg-gray-800 rounded-xl shadow-lg overflow-hidden border border-gray-700">
            {loading ? (
                <div className="p-12 text-center text-gray-500">Caricamento dati...</div>
            ) : (
                <>
                   {activeTab === 'users' && (
                       <div className="overflow-x-auto">
                           <table className="min-w-full divide-y divide-gray-700">
                               <thead className="bg-gray-900/50">
                                   <tr>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Utente</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ruolo</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stato</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Azioni</th>
                                   </tr>
                               </thead>
                               <tbody className="bg-gray-800 divide-y divide-gray-700">
                                   {filteredUsers.map(u => (
                                       <tr key={u._id} className={u.isDeleted ? 'bg-red-900/10' : ''}>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                               <div className="flex items-center">
                                                   <div className="flex-shrink-0 h-10 w-10 rounded-full bg-indigo-900/30 flex items-center justify-center text-indigo-400 font-bold border border-indigo-900/50">
                                                       {u.name.charAt(0)}
                                                   </div>
                                                   <div className="ml-4">
                                                       <div className="text-sm font-medium text-white">{u.name} {u.surname}</div>
                                                       <div className="text-sm text-gray-500">{u.email}</div>
                                                   </div>
                                               </div>
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${u.role === UserRole.ASSOCIAZIONE ? 'bg-purple-900/30 text-purple-400' : 'bg-green-900/30 text-green-400'}`}>
                                                    {u.role}
                                                </span>
                                                {u.isVerified && (
                                                    <span className="ml-2 text-indigo-400" title="Verificato">
                                                        <CheckCircle className="w-4 h-4 inline" />
                                                    </span>
                                                )}
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                               {u.isDeleted ? (
                                                   <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-red-900/30 text-red-400">
                                                       Deleted
                                                   </span>
                                               ) : (
                                                   <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-900/30 text-green-400">
                                                       Active
                                                   </span>
                                               )}
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2">
                                               <button 
                                                    onClick={() => handleViewTickets(u._id, u.name)}
                                                    className="text-indigo-400 hover:text-indigo-300 bg-indigo-950 p-2 rounded-full transition"
                                                    title="Vedi Voucher"
                                                >
                                                    <TicketIcon className="w-4 h-4" />
                                               </button>

                                               {u.role === UserRole.ASSOCIAZIONE && (
                                                   <button 
                                                       onClick={() => handleVerifyUser(u._id)}
                                                       className={`${u.isVerified ? 'text-orange-400 bg-orange-900/20' : 'text-green-400 bg-green-900/20'} p-2 rounded-full hover:opacity-80 transition`}
                                                       title={u.isVerified ? "Revoca Verifica" : "Verifica"}
                                                   >
                                                       {u.isVerified ? <XCircle className="w-4 h-4"/> : <CheckCircle className="w-4 h-4"/>}
                                                   </button>
                                               )}

                                               {u.isDeleted && (
                                                   <button 
                                                       onClick={() => handleRestoreUser(u._id)}
                                                       className="text-green-400 bg-green-900/20 p-2 rounded-full hover:bg-green-900/40 transition"
                                                       title="Ripristina Account"
                                                   >
                                                       <RefreshCw className="w-4 h-4" />
                                                   </button>
                                               )}
                                           </td>
                                       </tr>
                                   ))}
                               </tbody>
                           </table>
                       </div>
                   )}

                   {activeTab === 'events' && (
                       <div className="overflow-x-auto">
                           <table className="min-w-full divide-y divide-gray-700">
                               <thead className="bg-gray-900/50">
                                   <tr>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Evento</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Organizzatore</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stato</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Azioni</th>
                                   </tr>
                               </thead>
                               <tbody className="bg-gray-800 divide-y divide-gray-700">
                                   {filteredEvents.map(e => (
                                       <tr key={e._id} className={e.status === 'deleted' ? 'bg-red-900/10 opacity-70' : ''}>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                               <div className="flex items-center">
                                                    <div className="h-10 w-10 flex-shrink-0 bg-gray-900 rounded-md overflow-hidden border border-gray-700">
                                                        <img className="h-full w-full object-cover" src={e.image} alt="" />
                                                    </div>
                                                    <div className="ml-4">
                                                        <div className="text-sm font-medium text-white">{e.title}</div>
                                                        <div className="text-sm text-gray-500">{e.location}</div>
                                                    </div>
                                               </div>
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-400">
                                               {typeof e.organization === 'object' ? e.organization.name : 'Unknown'}
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-400">
                                               {new Date(e.date).toLocaleDateString()}
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                                                    ${e.status === 'active' || !e.status ? 'bg-green-900/30 text-green-400' : ''}
                                                    ${e.status === 'archived' ? 'bg-gray-900 text-gray-400' : ''}
                                                    ${e.status === 'deleted' ? 'bg-red-900/30 text-red-400' : ''}
                                                `}>
                                                    {e.status || 'active'}
                                                </span>
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap flex items-center space-x-2 text-sm">
                                               <button 
                                                   onClick={() => handleViewStats(e)}
                                                   className="text-indigo-400 hover:text-white hover:bg-indigo-600 border border-indigo-900/50 hover:border-indigo-600 px-3 py-1 rounded-md transition flex items-center font-medium"
                                               >
                                                   <BarChart className="w-4 h-4 mr-2" />
                                                   Stats
                                               </button>
                                               <button 
                                                    onClick={() => navigate(`/events/${e._id}/attendees`)}
                                                    className="text-teal-400 hover:text-white hover:bg-teal-600 border border-teal-900/50 hover:border-teal-600 px-3 py-1 rounded-md transition flex items-center font-medium"
                                                >
                                                    <Users className="w-4 h-4 mr-2" />
                                                    Lista
                                                </button>
                                           </td>
                                       </tr>
                                   ))}
                               </tbody>
                           </table>
                       </div>
                   )}

                   {activeTab === 'reports' && (
                       <div className="overflow-x-auto">
                           <table className="min-w-full divide-y divide-gray-700">
                               <thead className="bg-gray-900/50">
                                   <tr>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Evento Segnalato</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Motivo</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Reporter</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Azioni</th>
                                   </tr>
                               </thead>
                               <tbody className="bg-gray-800 divide-y divide-gray-700">
                                   {reports.length > 0 ? reports.map(r => (
                                       <tr key={r._id}>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="flex items-center">
                                                    <img src={r.eventId.image} className="w-8 h-8 rounded object-cover mr-3 border border-gray-700" />
                                                    <span className="text-sm font-bold text-white">{r.eventId.title}</span>
                                                </div>
                                           </td>
                                           <td className="px-6 py-4">
                                               <span className="bg-red-900/20 text-red-400 px-2 py-1 rounded-md text-xs font-bold border border-red-900/30">
                                                   {r.reason}
                                               </span>
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                               {new Date(r.createdAt).toLocaleDateString()}
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-400">
                                               {r.reporterId.name} ({r.reporterId.email})
                                           </td>
                                           <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                                               <button 
                                                   onClick={() => handleOpenModeration(r.eventId)}
                                                   className="bg-red-600 text-white px-3 py-1 rounded-md hover:bg-red-700 transition shadow-lg"
                                               >
                                                   Gestisci
                                               </button>
                                           </td>
                                       </tr>
                                   )) : (
                                       <tr>
                                           <td colSpan={5} className="px-6 py-12 text-center text-gray-500 italic">
                                               Nessuna segnalazione in sospeso.
                                           </td>
                                       </tr>
                                   )}
                               </tbody>
                           </table>
                       </div>
                   )}
                </>
            )}
        </div>
      </div>

      {/* TICKETS MODAL */}
      {isTicketModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
              <div className="bg-gray-800 rounded-xl shadow-2xl max-w-2xl w-full max-h-[80vh] flex flex-col border border-gray-700">
                  <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
                      <h3 className="text-xl font-bold text-white">Voucher di {selectedUserName}</h3>
                      <button onClick={() => setIsTicketModalOpen(false)} className="text-gray-400 hover:text-white transition">
                          <XCircle className="w-6 h-6" />
                      </button>
                  </div>
                  <div className="p-6 overflow-y-auto flex-1 bg-gray-800">
                      {modalLoading ? (
                          <div className="text-center py-8 text-gray-500">Caricamento voucher...</div>
                      ) : selectedUserTickets.length === 0 ? (
                          <div className="text-center py-8 text-gray-500 italic">Nessun voucher trovato per questo utente.</div>
                      ) : (
                          <div className="space-y-4">
                              {selectedUserTickets.map(ticket => (
                                  <div key={ticket._id} className="border border-gray-700 rounded-lg p-4 flex justify-between items-start bg-gray-900/40 hover:bg-gray-750 transition shadow-sm">
                                      <div>
                                          <p className="font-bold text-white">{ticket.event.title}</p>
                                          <p className="text-sm text-gray-500">{new Date(ticket.event.date).toLocaleDateString()}</p>
                                          <p className="text-[10px] text-indigo-400 mt-1 font-mono uppercase tracking-wider">{ticket.qrCodeId}</p>

                                          {ticket.matricola && (
                                              <p className="text-xs text-gray-300 mt-2 font-semibold flex items-center bg-gray-900 border border-gray-700 rounded px-2 py-1 w-fit shadow-inner">
                                                  <GraduationCap className="w-3 h-3 mr-1 text-indigo-400" />
                                                  Mat: {ticket.matricola}
                                              </p>
                                          )}
                                      </div>
                                      <div className="text-right flex flex-col items-end">
                                          {getTicketStatusBadge(ticket)}

                                          <p className="text-[10px] text-gray-600 mt-2 uppercase tracking-wide">
                                              Acquistato: {new Date(ticket.purchaseDate).toLocaleDateString()}
                                          </p>

                                          {(ticket.entryTime || ticket.exitTime) && (
                                              <div className="mt-2 text-[10px] text-gray-400 bg-gray-950 p-2 rounded border border-gray-700 shadow-sm w-fit">
                                                  {ticket.entryTime && (
                                                      <div className="flex items-center justify-end whitespace-nowrap">
                                                          <Clock className="w-3 h-3 mr-1 text-green-500" /> 
                                                          In: {new Date(ticket.entryTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                                      </div>
                                                  )}
                                                  {ticket.exitTime && (
                                                      <div className="flex items-center justify-end mt-1 whitespace-nowrap">
                                                          <Clock className="w-3 h-3 mr-1 text-blue-500" />
                                                          Out: {new Date(ticket.exitTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                                      </div>
                                                  )}
                                              </div>
                                          )}
                                      </div>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>
                  <div className="p-4 border-t border-gray-700 bg-gray-900/50 rounded-b-xl text-right">
                      <button onClick={() => setIsTicketModalOpen(false)} className="px-4 py-2 bg-gray-700 text-gray-300 rounded-lg font-medium hover:bg-gray-600 transition border border-gray-600">
                          Chiudi
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* MODERATION MODAL */}
      {isModModalOpen && modTargetEvent && (
          <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
              <div className="bg-gray-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-gray-700">
                  <div className="bg-red-600/90 p-6 text-white flex justify-between items-center shadow-lg">
                      <h3 className="text-xl font-bold flex items-center">
                          <AlertTriangle className="w-6 h-6 mr-2" />
                          Rimuovi Evento Segnalato
                      </h3>
                      <button onClick={() => setIsModModalOpen(false)}>
                          <X className="w-6 h-6" />
                      </button>
                  </div>
                  <div className="p-6 space-y-4">
                      <p className="text-gray-300">
                          Stai per rimuovere definitivamente l'evento: <strong className="text-red-400 underline">{modTargetEvent.title}</strong>.
                      </p>
                      <div>
